class HandlerRegistry:
    """Registry for dynamically managing message handlers."""

    def __init__(self):
        self._handlers: Dict[str, MessageHandler] = {}

    def register(self, handler: MessageHandler):
        """Register a handler instance."""
        self._handlers[handler.message_type] = handler
        logger.info(f"Registered handler for message type: {handler.message_type}")

    def unregister(self, message_type: str):
        """Unregister a handler by message type."""
        if message_type in self._handlers:
            del self._handlers[message_type]
            logger.info(f"Unregistered handler for message type: {message_type}")

    def get_handler(self, message_type: str) -> Optional[MessageHandler]:
        """Get a handler for the given message type."""
        return self._handlers.get(message_type)

    def get_registered_types(self) -> list:
        """Return list of registered message types."""
        return list(self._handlers.keys())

    def auto_register(self, handler_classes: list):
        """Auto-register a list of handler classes."""
        for handler_cls in handler_classes:
            if isinstance(handler_cls, type) and issubclass(handler_cls, MessageHandler) and handler_cls != MessageHandler:
                self.register(handler_cls())


class DeadLetterHandler:
    """Handles messages that fail processing repeatedly."""

    def __init__(self, sqs_client, dlq_url: Optional[str] = None):
        self._sqs_client = sqs_client
        self._dlq_url = dlq_url

    def send_to_dlq(self, message: dict, error: str):
        """Send a failed message to the dead letter queue."""
        if not self._dlq_url:
            logger.warning("No DLQ configured. Failed message will be lost after visibility timeout.")
            return

        try:
            body = json.loads(message.get("Body", "{}"))
            body["_error"] = str(error)
            body["_original_message_id"] = message.get("MessageId", "unknown")

            self._sqs_client.send_message(
                QueueUrl=self._dlq_url,
                MessageBody=json.dumps(body),
                MessageAttributes={
                    "ErrorType": {
                        "DataType": "String",
                        "StringValue": type(error).__name__ if isinstance(error, Exception) else "Error"
                    }
                }
            )
            logger.info(f"Sent failed message {message.get('MessageId')} to DLQ")
        except ClientError as e:
            logger.error(f"Failed to send message to DLQ: {e}")


class MessageProcessor:
    """Core message processor that parses and routes messages to handlers."""

    def __init__(self, registry: HandlerRegistry):
        self._registry = registry

    def process(self, raw_message: dict) -> dict:
        """Parse a raw SQS message and route it to the appropriate handler."""
        message_id = raw_message.get("MessageId", "unknown")
        body_str = raw_message.get("Body", "{}")

        try:
            body = json.loads(body_str)
        except json.JSONDecodeError as e:
            raise ValueError(f"Invalid JSON in message {message_id}: {e}")

        # Support SNS-wrapped messages
        if "Message" in body and "TopicArn" in body:
            logger.info(f"Unwrapping SNS message for {message_id}")
            try:
                body = json.loads(body["Message"])
            except json.JSONDecodeError as e:
                raise ValueError(f"Invalid JSON in SNS message body: {e}")

        message_type = body.get("type") or body.get("message_type") or body.get("action")
        if not message_type:
            raise ValueError(f"Message {message_id} missing 'type', 'message_type', or 'action' field")

        payload = body.get("payload") or body.get("data") or body
        handler = self._registry.get_handler(message_type)

        if not handler:
            available = self._registry.get_registered_types()
            raise ValueError(
                f"No handler registered for message type '{message_type}'. "
                f"Available types: {available}"
            )

        logger.info(f"Processing message {message_id} with type '{message_type}'")
        result = handler.handle(payload)
        result["message_id"] = message_id
        result["message_type"] = message_type
        return result


class SQSWorker:
    """
    SQS Worker that polls messages from a queue and processes them
    using registered handlers.
    """

    def __init__(
        self,
        queue_url: str,
        region_name: str = "us-east-1",
        max_messages: int = 10,
        wait_time_seconds: int = 20,
        visibility_timeout: int = 30,
        dlq_url: Optional[str] = None,
        max_retries: int = 3,
        aws_access_key_id: Optional[str] = None,
        aws_secret_access_key: Optional[str] = None,
        endpoint_url: Optional[str] = None,
    ):
        self._queue_url = queue_url
        self._max_messages = max_messages
        self._wait_time_seconds = wait_time_seconds
        self._visibility_timeout = visibility_timeout
        self._max_retries = max_retries
        self._running = False
        self._processed_count = 0
        self._error_count = 0

        # Build SQS client
        client_kwargs = {"region_name": region_name}
        if aws_access_key_id and aws_secret_access_key:
            client_kwargs["aws_access_key_id"] = aws_access_key_id
            client_kwargs["aws_secret_access_key"] = aws_secret_access_key
        if endpoint_url:
            client_kwargs["endpoint_url"] = endpoint_url

        self._sqs_client = boto3.client("sqs", **client_kwargs)

        # Set up handler registry and processor
        self._registry = HandlerRegistry()
        self._processor = MessageProcessor(self._registry)
        self._dlq_handler = DeadLetterHandler(self._sqs_client, dlq_url)

        # Register default handlers
        self._registry.auto_register([
            EmailNotificationHandler,
            DataProcessingHandler,
            ImageResizeHandler,
            WebhookHandler,
            ReportGenerationHandler,
        ])

    @property
    def registry(self) -> HandlerRegistry:
        """Access the handler registry to register custom handlers."""
        return self._registry

    @property
    def stats(self) -> dict:
        """Return worker processing statistics."""
        return {
            "processed": self._processed_count,
            "errors": self._error_count,
            "running": self._running,
        }

    def _receive_messages(self) -> list:
        """Poll SQS for messages."""
        try:
            response = self._sqs_client.receive_message(
                QueueUrl=self._queue_url,
                MaxNumberOfMessages=self._max_messages,
                WaitTimeSeconds=self._wait_time_seconds,
                VisibilityTimeout=self._visibility_timeout,
                AttributeNames=["All"],
                MessageAttributeNames=["All"],
            )
            messages = response.get("Messages", [])
            if messages:
                logger.info(f"Received {len(messages)} message(s)")
            return messages
        except ClientError as e:
            logger.error(f"Error receiving messages: {e}")
            return []

    def _delete_message(self, receipt_handle: str):
        """Delete a successfully processed message from the queue."""
        try:
            self._sqs_client.delete_message(
                QueueUrl=self._queue_url,
                ReceiptHandle=receipt_handle,
            )
        except ClientError as e:
            logger.error(f"Error deleting message: {e}")

    def _change_message_visibility(self, receipt_handle: str, timeout: int):
        """Change the visibility timeout of a message (for retries)."""
        try:
            self._sqs_client.change_message_visibility(
                QueueUrl=self._queue_url,
                ReceiptHandle=receipt_handle,
                VisibilityTimeout=timeout,
            )
        except ClientError as e:
            logger.error(f"Error changing message visibility: {e}")

    def _get_receive_count(self, message: dict) -> int:
        """Get the approximate receive count for a message."""
        attributes = message.get("Attributes", {})
        return int(attributes.get("ApproximateReceiveCount", 1))

    def _process_message(self, message: dict):
        """Process a single SQS message."""
        message_id = message.get("MessageId", "unknown")
        receipt_handle = message["ReceiptHandle"]
        receive_count = self._get_receive_count(message)

        try:
            result = self._processor.process(message)
            self._delete_message(receipt_handle)
            self._processed_count += 1
            logger.info(f"Successfully processed message {message_id}: {result}")

        except Exception as e:
            self._error_count += 1
            logger.error(f"Error processing message {message_id} (attempt {receive_count}): {e}")

            if receive_count >= self._max_retries:
                logger.warning(
                    f"Message {message_id} exceeded max retries ({self._max_retries}). "
                    f"Sending to DLQ."
                )
                self._dlq_handler.send_to_dlq(message, str(e))
                self._delete_message(receipt_handle)
            else:
                # Exponential backoff for retry
                backoff = min(2 ** receive_count, 300)
                logger.info(f"Scheduling retry for message {message_id} in {backoff}s")
                self._change_message_visibility(receipt_handle, backoff)

    def process_batch(self, messages: list):
        """Process a batch of messages."""
        for message in messages:
            if not self._running:
                break
            self._process_message(message)

    def start(self):
        """Start the worker polling loop."""
        self._running = True
        logger.info(f"Starting SQS worker. Queue: {self._queue_url}")
        logger.info(f"Registered handlers: {self._registry.get_registered_types()}")

        # Handle graceful shutdown signals
        def signal_handler(signum, frame):
            logger.info(f"Received signal {signum}. Shutting down gracefully...")
            self.stop()

        signal.signal(signal.SIGINT, signal_handler)
        signal.signal(signal.SIGTERM, signal_handler)

        while self._running:
            try:
                messages = self._receive_messages()
                if messages:
                    self.process_batch(messages)
                else:
                    logger.debug("No messages received. Continuing to poll...")
            except Exception as e:
                logger.error(f"Unexpected error in polling loop: {e}")
                if self._running:
                    time.sleep(5)  # Brief pause before retrying

        logger.info(f"Worker stopped. Stats: {self.stats}")

    def stop(self):
        """Stop the worker gracefully."""
        logger.info("Stopping SQS worker...")
        self._running = False


